"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[435],{1010:e=>{e.exports=JSON.parse('{"functions":[],"properties":[{"name":"TrackInstances","desc":"Whether the sandbox should track `Instance`s.\\n\\nIf this is enabled, the sandbox will keep track of all `Instance`s\\nthat are created in the sandbox. It will also track all `Instance`s \\nthat are accessed in the sandbox.\\n\\nThis will allow for forcible cleanup of `Instance`s that are created \\nin the sandbox, but it may cause performance issues if there are a lot \\nof `Instance`s being created.","lua_type":"boolean","readonly":true,"source":{"line":43,"path":"src/Config.luau"}},{"name":"TrackRBXScriptConnections","desc":"Whether the sandbox should track `RBXScriptConnection`s.\\n\\nIf this is enabled, the sandbox will keep track of all \\n`RBXScriptConnection`s that are created in the sandbox.\\nThis will allow for forcible cleanup of `RBXScriptConnection`s \\nthat are created in the sandbox, but it may cause performance \\nissues if there are a lot of `RBXScriptConnection`s being created.","lua_type":"boolean","readonly":true,"source":{"line":58,"path":"src/Config.luau"}},{"name":"AllowParallelLuau","desc":"Whether the sandbox will allow Actors (Parallel Luau)\\nto be used in the sandbox.\\n\\nWhen this is `false`, any call to the sandboxer from an\\nActor will error. Each Actor creates its own instance of\\nthis module, so if this is problematic (and it likely will\\nbe because of memory usage), set this to `false`. \\nWhen this is `true`, the sandboxer will work as expected in \\nActors, but it may cause performance issues and increased \\nmemory usage. `task.synchronize()` and `task.desynchronize()` \\nwill work as usual, but errors regarding property sets while\\nin parallel mode might not make sense.","lua_type":"boolean","readonly":true,"source":{"line":78,"path":"src/Config.luau"}}],"types":[],"name":"Config","desc":"A module for configuring various aspects of the sandbox.","source":{"line":26,"path":"src/Config.luau"}}')}}]);